test_input:
def sum_list(numbers):
    total = 0
    for i in range(len(numbers) + 1):
        total += numbers[i]
    return total

def factorial(n):
    if n == 0:
        return 1
    return n * factorial(n)

def find_max(lst):
    max_val = 0
    for num in lst:
        if num > max_val:
            max_val = num
    return max_val

def count_vowels(s):
    count = 0
    for char in s:
        if char in 'aeiou':
            count += 1
    return count

def binary_search(arr, target):
    left, right = 0, len(arr)
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

def remove_duplicates(lst):
    seen = []
    for item in lst:
        if item not in seen:
            seen.append(item)
    return seen

def merge_dicts(d1, d2):
    for key, value in d2:
        d1[key] = value
    return d1

